var input = inputs.Length > 0 && inputs[0] != null ? inputs[0]! :
        new PixelBuffer(context.TileSize, context.TileSize);
    var thickness = Math.Max(1, GetInt(parameters, "thickness", 1));
    var edgeThreshold = GetFloat(parameters, "threshold", 0.3f);
    var lineColor = GetColor(parameters, "lineColor", Colors.Black);
    var mode = GetChoice(parameters, "mode", "outside");
    var detectMode = GetChoice(parameters, "detectMode", "alpha");
    var softness = GetFloat(parameters, "softness", 0f);

    var size = context.TileSize;
    var buffer = input.Clone();
    var (edgeMask, edgeMagnitude) = ComputeEdgeMask(input, size, edgeThreshold, detectMode);

    var lR = lineColor.R / 255f;
    var lG = lineColor.G / 255f;
    var lB = lineColor.B / 255f;

    // Dilate edge mask based on thickness
    var dilatedEdges = DilateEdges(edgeMask, size, thickness);

    buffer.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = buffer.GetPixel(x, y);
        var edge = dilatedEdges[y * size + x];

        // Soft edge: use SmoothStep on continuous magnitude with softness-controlled threshold.
        var edgeAlpha = softness > 0f
            ? SmoothStepEdge(edgeMagnitude[y * size + x], softness)
            : edge;

        if (edgeAlpha <= 0f) return;

        if (mode == "outside")
        {
            // Only draw outline on transparent/background areas
            if (a < 0.5f)
            {
                buffer.SetPixel(x, y, lR, lG, lB, edgeAlpha);
            }
        }
        else if (mode == "inside")
        {
            // Draw outline inside the alpha > 0 region
            if (a > 0.5f)
            {
                buffer.SetPixel(x, y,
                    Lerp(r, lR, edgeAlpha),
                    Lerp(g, lG, edgeAlpha),
                    Lerp(b, lB, edgeAlpha), 1f);
            }
        }
        else if (mode == "glow")
        {
            // Glow: colored outline over transparent areas near edges
            if (a < 0.8f)
            {
                var glow = edgeAlpha * 0.7f;
                buffer.SetPixel(x, y, lR * glow, lG * glow, lB * glow, glow);
            }
        }
        else // both
        {
            buffer.SetPixel(x, y, lR, lG, lB, Math.Max(edgeAlpha, a));
        }
    });

    return buffer;

private static (float[] Binary, float[] Continuous) ComputeEdgeMask(PixelBuffer input, int size, float threshold, string detectMode)
{
    var binary = new float[size * size];
    var continuous = new float[size * size];

    // Sobel kernels (3x3)
    var sobelX = new[,] { { -1, 0, 1 }, { -2, 0, 2 }, { -1, 0, 1 } };
    var sobelY = new[,] { { -1, -2, -1 }, { 0, 0, 0 }, { 1, 2, 1 } };

    for (var y = 0; y < size; y++)
    {
        for (var x = 0; x < size; x++)
        {
            float gx = 0, gy = 0;

            for (var ky = -1; ky <= 1; ky++)
            {
                for (var kx = -1; kx <= 1; kx++)
                {
                    var sx = (x + kx + size) % size;
                    var sy = (y + ky + size) % size;
                    var (r, g, b, a) = input.GetPixel(sx, sy);

                    var val = detectMode switch
                    {
                        "alpha" => a,
                        "luminance" => r * 0.299f + g * 0.587f + b * 0.114f,
                        _ => (r + g + b) / 3f
                    };

                    gx += val * sobelX[ky + 1, kx + 1];
                    gy += val * sobelY[ky + 1, kx + 1];
                }
            }

            var magnitude = MathF.Sqrt(gx * gx + gy * gy);
            // Normalize magnitude: Sobel output range is roughly [-4, 4] per channel
            // for [0,1] input, so max magnitude is ~5.66
            continuous[y * size + x] = Math.Clamp(magnitude / 4f, 0f, 1f);
            binary[y * size + x] = magnitude > threshold ? 1f : 0f;
        }
    }

    return (binary, continuous);
}

/// <summary>
/// SmoothStep mapped through [edge0, edge1] for soft edge falloff.
/// </summary>
private static float SmoothStepEdge(float x, float softness)
{
    var edge0 = MathF.Max(0f, 0.15f - softness * 0.12f);
    var edge1 = MathF.Min(1f, 0.15f + softness * 0.6f);
    var t = Math.Clamp((x - edge0) / (edge1 - edge0 + 0.0001f), 0f, 1f);
    return t * t * (3f - 2f * t);
}

private static float[] DilateEdges(float[] edges, int size, int thickness)
{
    if (thickness <= 1) return edges;
    // Reuse a single temp buffer across dilation iterations
    var temp = new float[size * size];
    var src = edges;
    var dst = temp;

    for (var iter = 1; iter < thickness; iter++)
    {
        // Clear destination
        Array.Clear(dst);

        for (var y = 0; y < size; y++)
        {
            for (var x = 0; x < size; x++)
            {
                if (src[y * size + x] > 0f)
                {
                    dst[y * size + x] = 1f;
                    continue;
                }

                // Check neighbors in a diamond pattern
                for (var dy = -1; dy <= 1; dy++)
                {
                    for (var dx = -1; dx <= 1; dx++)
                    {
                        if (dx == 0 && dy == 0) continue;
                        var nx = (x + dx + size) % size;
                        var ny = (y + dy + size) % size;
                        if (src[ny * size + nx] > 0f)
                        {
                            dst[y * size + x] = 1f;
                            goto next;
                        }
                    }
                }
                next:;
            }
        }

        // Swap buffers for next iteration
        (src, dst) = (dst, src);
    }

    // If we ended on temp, copy to edges
    if (thickness % 2 == 0)
    {
        Array.Copy(temp, edges, temp.Length);
    }

    return edges;
    }
